import { useState } from "react";
import Input from "../components/ui/Input";
import Card from "../components/ui/Card";
import Btn from "../components/ui/btn";

const StudentsPage = ({ students, onAssign, onRemove }) => {
  const [search, setSearch] = useState("");
  const filtered = students.filter(s =>
    s.name?.toLowerCase().includes(search.toLowerCase()) ||
    s.email?.toLowerCase().includes(search.toLowerCase())
  );
  
  return (
    <div>
      <h2 style={{ fontSize: 24, fontWeight: 800, color: "#1e293b", marginBottom: 24 }}>Student Management</h2>
      <Input placeholder="Search students..." value={search} onChange={e => setSearch(e.target.value)} />
      <Card style={{ padding: 0, overflow: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e2e8f0" }}>
              <th style={{ padding: 12, textAlign: "left" }}>Name</th>
              <th style={{ padding: 12, textAlign: "left" }}>Email</th>
              <th style={{ padding: 12, textAlign: "left" }}>Course</th>
              <th style={{ padding: 12, textAlign: "left" }}>Room</th>
              <th style={{ padding: 12, textAlign: "left" }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map(s => (
              <tr key={s.id} style={{ borderBottom: "1px solid #f1f5f9" }}>
                <td style={{ padding: 12 }}>{s.name}</td>
                <td style={{ padding: 12 }}>{s.email}</td>
                <td style={{ padding: 12 }}>{s.course}</td>
                <td style={{ padding: 12 }}>{s.roomId || "Unassigned"}</td>
                <td style={{ padding: 12 }}>
                  {!s.roomId && (
                    <Btn onClick={() => onAssign(s)} style={{ padding: "5px 12px", fontSize: 12 }}>
                      Assign Room
                    </Btn>
                  )}
                  {s.roomId && (
                    <Btn variant="danger" onClick={() => onRemove(s.id)} style={{ padding: "5px 12px", fontSize: 12 }}>
                      Remove
                    </Btn>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </Card>
    </div>
  );
};

export default StudentsPage;
